这是主要的 JavaScript 文件，位于 `myapp/backend/js` 目录下。文件内容如下：

```javascript
// 启动 Python 数据分析服务
function startDataAnalysisService() {
    const pythonProcess = spawn('python', ['student_data_analysis.py'], {
        cwd: __dirname,
        stdio: ['ignore', 'pipe', 'pipe']
    });

    pythonProcess.stdout.on('data', (data) => {
        console.log('[student_data_analysis.py]: ${data.toString()}');
    });

    pythonProcess.stderr.on('data', (data) => {
        console.error('[student_data_analysis.py ERROR]: ${data.toString()}');
    });

    pythonProcess.on('close', (code) => {
        console.log('[student_data_analysis.py] 进程退出, 退出码: ${code}');
        // 如果进程意外退出，尝试重启
        if (code !== 0) {
            console.log('尝试重新启动 student_data_analysis.py...');
            setTimeout(startDataAnalysisService, 5000);
        }
    });

    return pythonProcess;
}

// 启动学生数据分析服务
function startStudentDataAnalysisService() {
    const pythonProcess = spawn('python', ['student_data_analysis.py'], {
        cwd: __dirname,
        stdio: ['ignore', 'pipe', 'pipe']
    });

    pythonProcess.stdout.on('data', (data) => {
        console.log('[student_data_analysis.py]: ${data.toString()}');
    });

    pythonProcess.stderr.on('data', (data) => {
        console.error('[student_data_analysis.py ERROR]: ${data.toString()}');
    });
}
```

